const input = $input.first().json || {};
let rows = input.result || [];
if (typeof rows === 'string') { try { rows = JSON.parse(rows); } catch(e) { rows = []; } }
if (!Array.isArray(rows)) rows = [];

const esc = s => String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');

// \u0413\u0435\u043d\u0435\u0440\u0430\u0442\u043e\u0440 \u043f\u0435\u0440\u0441\u043e\u043d\u0430\u043b\u044c\u043d\u044b\u0445 \u043f\u0440\u043e\u043c\u043e\u043a\u043e\u0434\u043e\u0432
function genCode(email) {
  const base = String(email || 'USER').replace(/[^a-zA-Z0-9]/g,'').toUpperCase().slice(0,4).padEnd(4,'X');
  const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
  let rand = '';
  for (let i=0; i<4; i++) rand += chars[Math.floor(Math.random()*chars.length)];
  return 'WB' + base + rand;
}

// \u0414\u043e\u0431\u0430\u0432\u043b\u044f\u0435\u043c \u043f\u0440\u043e\u043c\u043e\u043a\u043e\u0434\u044b \u0438 \u043a\u0430\u043d\u0430\u043b
rows = rows.map(r => {
  let channel;
  if (r.tg_id) channel = 'telegram';
  else if (r.phone) channel = 'sms';
  else channel = 'email';
  return { ...r, promocode: genCode(r.email), suggested_channel: channel };
});

if (rows.length === 0) {
  return [{json: { skip: true, count: 0, text: null, csv: null, rows: [] }}];
}

// CSV
const headers = ['rank','priority','email','phone','telegram_id','language','orders','ltv_eur','days_silent','last_order_date','fav_brand','fav_sku','fav_product_name','suggested_channel','promocode'];
const escCsv = v => { const s = String(v == null ? '' : v); return '"' + s.replace(/"/g,'""') + '"'; };
const csvLines = [headers.map(escCsv).join(',')];
rows.forEach((r, i) => {
  const priority = r.ltv_eur >= 1000 ? 'HIGH' : r.ltv_eur >= 500 ? 'MID' : 'LOW';
  csvLines.push([
    i+1, priority,
    r.email||'', r.phone||'', r.tg_id||'', r.language||'ru',
    r.orders, r.ltv_eur, r.days_silent, r.last_dt,
    r.fav_brand||'', r.fav_sku||'', (r.fav_name||'').slice(0,60),
    r.suggested_channel, r.promocode
  ].map(escCsv).join(','));
});
const csv = csvLines.join('\n');

// Telegram summary (top-10)
const totalLtv = rows.reduce((s,r) => s + Number(r.ltv_eur||0), 0);
const high = rows.filter(r => r.ltv_eur >= 1000).length;
const mid = rows.filter(r => r.ltv_eur >= 500 && r.ltv_eur < 1000).length;
const low = rows.length - high - mid;

const topLines = rows.slice(0, 10).map((r, i) => {
  const ch = r.suggested_channel === 'telegram' ? '\ud83d\udce9' : r.suggested_channel === 'sms' ? '\u260e\ufe0f' : '\u2709\ufe0f';
  return (i+1) + '. ' + ch + ' <code>' + esc(r.email || '(no email)') + '</code> \u2014 <b>\u20ac' + r.ltv_eur + '</b>, ' + r.orders + ' \u0437\u0430\u043a., ' + r.days_silent + '\u0434 \u0442\u0438\u0448\u0438\u043d\u044b \u2192 <code>' + r.promocode + '</code>';
}).join('\n');

const today = new Date().toISOString().slice(0,10);
const text = '\ud83d\udce8 <b>Winback Weekly \u2014 \u043d\u043e\u0432\u044b\u0435 At Risk Champions</b>\n<i>' + today + ' | \u043f\u043e\u0440\u043e\u0433: LTV\u2265\u20ac200, \u0442\u0438\u0448\u0438\u043d\u0430 30-60\u0434, \u22653 \u0437\u0430\u043a\u0430\u0437\u0430</i>\n\n<b>' + rows.length + '</b> \u043a\u0430\u043d\u0434\u0438\u0434\u0430\u0442\u043e\u0432, \u0441\u0443\u043c\u043c\u0430\u0440\u043d\u044b\u0439 LTV <b>\u20ac' + totalLtv + '</b>\n\u2022 HIGH (\u20ac1000+): ' + high + '\n\u2022 MID (\u20ac500\u2013999): ' + mid + '\n\u2022 LOW (\u20ac200\u2013499): ' + low + '\n\n<b>\u0422\u043e\u043f-10:</b>\n' + topLines + '\n\n\u2192 \u041c\u0430\u043a\u0441\u0438\u043c: \u043f\u043e\u043b\u043d\u044b\u0439 CSV \u2014 \u0441\u043b\u0435\u0434\u0443\u044e\u0449\u0438\u043c \u0444\u0430\u0439\u043b\u043e\u043c.';

// \u0418\u043c\u044f \u0444\u0430\u0439\u043b\u0430
const filename = 'winback_' + today.replace(/-/g,'') + '.csv';

return [{
  json: { text, count: rows.length, total_ltv: totalLtv, rows, filename },
  binary: { data: { data: Buffer.from(csv, 'utf-8').toString('base64'), mimeType: 'text/csv', fileName: filename } }
}];
